(()=>{"use strict";self.addEventListener("push",t=>{let e;if(!t.data)return;try{e=t.data.json()}catch{e={title:"Islas",body:t.data.text(),type:"info",url:"/"}}let i={body:e.body,icon:"/favicon.ico",badge:"/favicon.ico",tag:`islas-${e.type}-${Date.now()}`,data:{url:e.url},vibrate:[100,50,100]};t.waitUntil(self.registration.showNotification(e.title,i).then(()=>self.clients.matchAll({type:"window"}).then(t=>{t.forEach(t=>{t.postMessage({type:"NOTIFICATION_SOUND",payload:e})})})))}),self.addEventListener("notificationclick",t=>{t.notification.close();let e=t.notification.data?.url||"/";t.waitUntil(self.clients.matchAll({type:"window",includeUncontrolled:!0}).then(t=>{for(let i of t)if(i.url.includes(self.location.origin)&&"focus"in i){i.focus(),i.navigate(e);return}return self.clients.openWindow(e)}))})})();